#nullable enable // autogenerated

using MVZ2.Metas;
using MVZ2.Talk;
using UnityEngine;


namespace MVZ2.Managers
{
    public class TalkManager : MonoBehaviour
    {
        public CharacterPortraitViewData GetPortraitViewData(TalkCharacterVariant variant)
        {
            var layers = new CharacterPortraitLayerViewData[variant.layers.Count];

            for (int i = 0; i < layers.Length; i++)
            {
                var layer = variant.layers[i];
                var sprite = Main.GetFinalSprite(layer.sprite);
                layers[i] = new CharacterPortraitLayerViewData()
                {
                    position = new Vector2(layer.positionX, variant.height - layer.positionY),
                    sprite = sprite
                };
            }
            return new CharacterPortraitViewData()
            {
                width = variant.width,
                height = variant.height,
                layers = layers
            };
        }
        public CharacterPortrait CreateCharacterPortrait()
        {
            var component = CreateComponent();
            return new CharacterPortrait(component);
        }
        public CharacterPortrait CreateCharacterPortrait(TalkCharacterVariant variant)
        {
            var portrait = CreateCharacterPortrait();
            portrait.ChangeVariant(GetPortraitViewData(variant));
            return portrait;
        }
        public CharacterPortraitComponent CreateComponent()
        {
            var comp = Instantiate(portraitPrefab, portraitRoot);
            comp.gameObject.SetActive(true);
            return comp;
        }
        public MainManager Main => MainManager.Instance;
        public Transform portraitRoot = null!;
        public CharacterPortraitComponent portraitPrefab = null!;
    }
}
